local G = DYCInfoPanel local require = G.DYCModRequire local odwutil = require( "dyc_odwutil" ) local ShowObjectDetail = odwutil.ShowObjectDetail local FollowObject = odwutil.FollowObject local function FollowTarget(inst) local odw = G.objectDetailWindow if odw and odw.shown and inst and odw.focusedObject and odw.focusedObject == inst then FollowObject(inst) end end local lastTarget = nil local lastX, lastY, lastZ = 0x3e7, 0x3e7, 0x3e7 local function HighlightActionItem(self, itemIndex, itemInActions, ...) if TheInput:ControllerAttached() then if itemIndex then local owner = self.owner local pc = owner and owner.components.playercontroller local target = pc and pc.controller_target if target ~= lastTarget then ShowObjectDetail(target) end if target then local x, y, z = TheSim:GetScreenPos(target.Transform:GetWorldPosition()) if x ~= lastX or y ~= lastY or z ~= lastZ then FollowTarget(target) lastX, lastY, lastZ = x, y, z end end lastTarget = target else if lastTarget ~= nil then ShowObjectDetail() end lastTarget = nil end end return self.dycOldHighlightActionItem(self, itemIndex, itemInActions, ...) end local function DYCControls(self) self.dycOldHighlightActionItem = self.HighlightActionItem self.HighlightActionItem = HighlightActionItem end return DYCControls 